function msToTime(ms) {
let seg = Math.floor(ms / 1000)
let min = Math.floor(seg / 60)
let hr = Math.floor(min / 60)
let dia = Math.floor(hr / 24)
let ano = Math.floor(dia / 365)
seg %= 60
min %= 60
hr %= 24
dia %= 365
let partes = []
if (ano) partes.push(`${ano} бҙҖЙҙбҙҸ${ano > 1 ? 'кңұ' : ''}`)
if (dia) partes.push(`${dia} бҙ…ЙӘбҙҖ${dia > 1 ? 'кңұ' : ''}`)
if (hr) partes.push(`${hr} КңбҙҸКҖбҙҖ${hr > 1 ? 'кңұ' : ''}`)
if (min) partes.push(`${min} бҙҚЙӘЙҙбҙңбҙӣбҙҸ${min > 1 ? 'кңұ' : ''}`)
if (seg) partes.push(`${seg} кңұбҙҮЙўбҙңЙҙбҙ…бҙҸ${seg > 1 ? 'кңұ' : ''}`)
return partes.length ? partes.join(', ').replace(/,([^,]*)$/, ' e$1') : 'бҙҖЙўбҙҸКҖбҙҖ КңбҙҖ бҙ©бҙҸбҙңбҙ„бҙҸ'
}

