if(JSON.stringify(anotar).includes(from)) {
var i2 = anotar.map(i => i.grupo).indexOf(from)
if(JSON.stringify(anotar[i2].puxar).includes(q)) {
var i3 = anotar[i2].puxar.map(i => i.nota).indexOf(q)
}
}
