let prisaoDB = {};
let armasDB = {};

if (fs.existsSync(policiaPath)) policiaDB = JSON.parse(fs.readFileSync(policiaPath));
if (fs.existsSync(crimesPath)) crimesDB = JSON.parse(fs.readFileSync(crimesPath));
