    for (let i = 0; i < familia.filhos.length; i++) {
        const filho = familia.filhos[i];
        let nomeExibicao = '';
        let idExibicao = '';
        
        // Verifica se Г© um usuГЎrio real (adotado por @)
        if (filho.isUser === true && filho.id && filho.id.includes('@')) {
            const nomePuro = extrairNomePuro(filho.id);
            nomeExibicao = nomePuro ? `@${nomePuro}` : (filho.tipo === 'filho' ? 'Filho' : 'Filha');
            idExibicao = filho.id; // ID Г© o @ do WhatsApp
        } else {
            nomeExibicao = filho.nome || (filho.tipo === 'filho' ? 'Filho' : 'Filha');
            idExibicao = filho.id; // ID Г© numГ©rico
        }
        
        const tipoEmoji = (filho.tipo === 'filho') ? 'рҹ‘Ұ' : 'рҹ‘§';
        texto += `${i+1}Вә ${tipoEmoji} *${nomeExibicao}*\n`;
        texto += `   рҹҶ” ID: \`${idExibicao}\`\n`;
        if (filho.dataAdocao) {
            texto += `   рҹ“… Adotado em: ${filho.dataAdocao}\n`;
        }
        texto += `\n`;
    }
    texto += `вҖўв”Ҳв”ҲВ·в”ҲвҖўвҳҫвҖўв”Ҳв”Ҳв”ҲвҖўвҖўвңҰ вҳ© вңҰвҖўвҖўв”Ҳв”Ҳв”ҲвҖўвҳҪвҖўв”Ҳв”ҲВ·в”ҲвҖў`;

    // Monta lista de menГ§Гөes para os filhos que sГЈo usuГЎrios
    const mentions = [];
