    if (fs.existsSync(petsPath)) petsDB = JSON.parse(fs.readFileSync(petsPath));
    const meusPets = petsDB[alvo] || [];
    const totalPets = meusPets.length;
    
    let mediaFome = 0, mediaHigiene = 0;
    if (totalPets > 0) {
        mediaFome = Math.floor(meusPets.reduce((acc, p) => acc + p.fome, 0) / totalPets);
        mediaHigiene = Math.floor(meusPets.reduce((acc, p) => acc + p.higiene, 0) / totalPets);
    }

    const pixPath = './DADOS DO KEISEN/usuarios/pixkeys.json';
    let pixDB = {};
    if (fs.existsSync(pixPath)) pixDB = JSON.parse(fs.readFileSync(pixPath));
    const temChave = pixDB[alvo] ? true : false;
    const chavePix = temChave ? pixDB[alvo].chave : 'NГЈo cadastrada';

    // ========== SISTEMA DE SEXO/GГҠNERO ==========
    const sexoPath = './sexo.json';
    let sexoDB = {};
    if (fs.existsSync(sexoPath)) sexoDB = JSON.parse(fs.readFileSync(sexoPath));
    let sexo = sexoDB[alvo] || 'NГЈo definido';
    let emojiSexo = 'вқ“';
    if (sexo === 'Masculino') emojiSexo = 'рҹ‘Ё';
    else if (sexo === 'Feminino') emojiSexo = 'рҹ‘©';
    else if (sexo === 'NГЈo binГЎrio') emojiSexo = 'рҹҢҹ';

    // ========== SISTEMA DE CASAMENTO ==========
    const casamentoPath = './DADOS DO KEISEN/usuarios/casamentos.json';
    let casamentosDB = {};
    if (fs.existsSync(casamentoPath)) casamentosDB = JSON.parse(fs.readFileSync(casamentoPath));
    
    let statusNamoro = 'рҹ’” Solteiro(a)';
    let nomeConjugue = '';
    let dataCasamento = '';
    let sexoConjugue = '';
    
    for (let id in casamentosDB) {
        if (casamentosDB[id].pessoa1 === alvo) {
            statusNamoro = 'рҹ’Қ Casado(a)';
            nomeConjugue = casamentosDB[id].pessoa2.split('@')[0];
            dataCasamento = casamentosDB[id].data;
            sexoConjugue = sexoDB[casamentosDB[id].pessoa2] || 'NГЈo definido';
            break;
        } else if (casamentosDB[id].pessoa2 === alvo) {
            statusNamoro = 'рҹ’Қ Casado(a)';
            nomeConjugue = casamentosDB[id].pessoa1.split('@')[0];
            dataCasamento = casamentosDB[id].data;
            sexoConjugue = sexoDB[casamentosDB[id].pessoa1] || 'NГЈo definido';
            break;
        }
    }

    // ========== SISTEMA DE FAMГҚLIA/FILHOS ==========
    const familiaPath = './DADOS DO KEISEN/usuarios/familia.json';
    let familiaDB = {};
    if (fs.existsSync(familiaPath)) familiaDB = JSON.parse(fs.readFileSync(familiaPath));
    const meusFilhos = familiaDB[alvo]?.filhos || [];
    const totalFilhos = meusFilhos.length;
    
    // Calcula idade mГ©dia dos filhos
    let idadeMedia = 0;
    if (totalFilhos > 0) {
        let somaIdades = 0;
        for (const filho of meusFilhos) {
            const idade = Math.floor((Date.now() - new Date(filho.dataAdocao)) / (1000 * 60 * 60 * 24 * 30));
            somaIdades += idade;
        }
        idadeMedia = Math.floor(somaIdades / totalFilhos);
    }

    // ========== SISTEMA DE PATRIMГ”NIO ==========
    const patrimonio = saldo;
    let classeSocial = '';
    let emojiClasse = '';
    if (patrimonio >= 1000000) { classeSocial = 'Magnata'; emojiClasse = 'рҹ‘‘'; }
    else if (patrimonio >= 500000) { classeSocial = 'MilionГЎrio'; emojiClasse = 'рҹ’°'; }
    else if (patrimonio >= 100000) { classeSocial = 'Rico'; emojiClasse = 'рҹ’Һ'; }
    else if (patrimonio >= 50000) { classeSocial = 'Classe Alta'; emojiClasse = 'рҹҸ '; }
    else if (patrimonio >= 10000) { classeSocial = 'Classe MГ©dia'; emojiClasse = 'рҹҸЎ'; }
    else if (patrimonio >= 1000) { classeSocial = 'Classe Baixa'; emojiClasse = 'рҹ“Ұ'; }
    else { classeSocial = 'Fudido'; emojiClasse = 'рҹ’Җ'; }

    // ========== NГҚVEL DO JOGADOR ==========
    let nivel = 'рҹҢҹ Iniciante';
    let emojiNivel = 'рҹҢұ';
    if (saldo >= 1000000) { nivel = 'рҹ‘‘ LendГЎrio'; emojiNivel = 'рҹ‘‘'; }
    else if (saldo >= 500000) { nivel = 'рҹ’Һ Diamante'; emojiNivel = 'рҹ’Һ'; }
    else if (saldo >= 100000) { nivel = 'вӯҗ Ouro'; emojiNivel = 'вӯҗ'; }
    else if (saldo >= 50000) { nivel = 'рҹ”® Platina'; emojiNivel = 'рҹ”®'; }
    else if (saldo >= 10000) { nivel = 'рҹҘҲ Prata'; emojiNivel = 'рҹҘҲ'; }
    else if (saldo >= 1000) { nivel = 'рҹҘү Bronze'; emojiNivel = 'рҹҘү'; }
    else { nivel = 'рҹҢұ Iniciante'; emojiNivel = 'рҹҢұ'; }

    // ========== DATA DE ENTRADA ==========
    const dataEntrada = '01/01/2024';

    // ========== CONSTRГ“I O PERFIL ==========
    let perfil = `вҖўв”Ҳв”ҲВ·в”ҲвҖўвҳҫвҖўв”Ҳв”Ҳв”ҲвҖўвҖўвңҰ вҳ© вңҰвҖўвҖўв”Ҳв”Ҳв”ҲвҖўвҳҪвҖўв”Ҳв”ҲВ·в”ҲвҖў\n\n`;
    perfil += `рҹҺ® *PERFIL RPG* рҹҺ®\n`;
    perfil += `рҹ‘Ө @${nomeUser}\n\n`;
    perfil += `в”Ҳв”Ҳв”Ҳв”Ҳв”Ҳв”Ҳв”Ҳв”Ҳв”Ҳв”Ҳв”Ҳв”Ҳв”Ҳв”Ҳв”Ҳв”Ҳв”Ҳ\n\n`;
    
    // ========== SEГҮГғO PESSOAL ==========
    perfil += `рҹ“Ӣ *DADOS PESSOAIS* рҹ“Ӣ\n`;
    perfil += `${emojiSexo} Sexo: ${sexo}\n`;
