    finalMsg += `рҹҺӯ *Personagem:* ${jujutsuDB[usuario].nomePersonagem}\n`;
    finalMsg += `рҹ‘№ *Inimigo:* ${inimigo.nome} (${inimigo.rank})\n\n`;
